insert into wa_template (template_id, name, category, body, buttons, usage_count) values (30746, 'declined_advice', 'status', 'Hey {{name}}! I received the bank''s response. While we can''t get an approval today, the good news is that we should get it approved in the next 2-3 months! With a little work on your credit score, you''ll be ready in a few short months.

