insert into funnel_node (code, question, options) values ('income', 'Let''s GOOO! 🔥

Are you permanently employed and earn a net salary on your payslip of R8500 or more per month?

(Self Employed must earn a minimum per month)', '[{"title": "Yes sir!", "next": "qr:docs", "set": {"income": "yes"}}, {"title": "Not yet", "next": "qr:low income", "set": {"income": "no"}}, {"title": "It''s Complicated", "next": "ESCALATE", "set": {"income": "complicated"}}]'::jsonb);
insert into funnel_node (code, question, options) values ('missed_payments', 'Thats not bad news at all! As long as you are not behind on any payments or missed payments we will be able to assist!

Thats what makes us different! We fight for each one of our clients!

Which of the options fits you best??', '[{"title": "Let''s do it!", "next": "timeline"}, {"title": "Let me explain first", "next": "ESCALATE"}, {"title": "3+ Missed Payemnts", "next": "qr:badcredit"}]'::jsonb);
